import numpy as np

def beta_binomial_posterior(
    alpha: float, beta: float, k: int, n: int
) -> tuple[float, float]:
    posterior_alpha = alpha + k
    posterior_beta = beta + n - k
    return posterior_alpha, posterior_beta


def posterior_mean(alpha_post: float, beta_post: float) -> float:
    return alpha_post / (alpha_post + beta_post)


def posterior_mode(alpha_post: float, beta_post: float) -> float:
    if alpha_post <= 1 or beta_post <= 1:
        raise ValueError('Mode is undefined when alpha <= 1 or beta <= 1')
    return (alpha_post - 1) / (alpha_post + beta_post - 2)
